// components/chat/chat-header.tsx
"use client";

import { PanelLeftIcon } from "lucide-react";
import { memo } from "react";
import { Button } from "@/components/ui/button";
import { Sidebar } from "@/components/ui/Sidebar";
import { ThemeToggle } from "@/components/ui/theme-toggle";

function PureChatHeader() {
  const { state, toggleSidebar, isMobile } = Sidebar();

  if (state === "collapsed" && !isMobile) {
    return null;
  }

  return (
    <header className="sticky top-0 flex h-14 items-center gap-2 bg-background border-b px-4 z-10">
      {/* 移动端侧边栏切换按钮 */}
      <Button
        className="md:hidden"
        onClick={toggleSidebar}
        size="icon-sm"
        variant="ghost"
      >
        <PanelLeftIcon className="size-4" />
      </Button>

      {/* 标题 */}
      <h1 className="text-sm font-semibold ml-2">方圆智版 AI</h1>

      {/* 右侧操作区 */}
      <div className="ml-auto flex items-center gap-2">
        <ThemeToggle />
      </div>
    </header>
  );
}

export const ChatHeader = memo(PureChatHeader, () => true);